    const saltHex = Array.from(wrapSalt).map(b => b.toString(16).padStart(2, '0')).join('');
    const cacheKey = saltHex + ':' + (uid || '');
    const cached = _getCachedWrapKey(cacheKey);
    if (cached) return cached;
